class Solution {
public:
    long long repairCars(vector<int>& ranks, int cars) {
        sort(ranks.begin(), ranks.end());
        long long time = 0;
        for (int i = 0; i < ranks.size() && cars > 0; i++) {
            int carsRepaired = min(cars, ranks[i]);
            time += (long long)ranks[i] * carsRepaired * carsRepaired;
            cars -= carsRepaired;
        }
        return time;
    }
};
